import requests

def check_cloudpets_breach(email):
    url = f"https://haveibeenpwned.com/api/v3/breachedaccount/{email}"
    headers = {"hibp-api-key": "YOUR_API_KEY"}
    response = requests.get(url, headers=headers)

    if response.status_code == 200:
        breaches = response.json()
        for breach in breaches:
            if breach['Name'] == 'CloudPets':
                print(f"Your email was affected in the CloudPets breach on {breach['BreachDate']}.")
                return True
    return False

# Example usage:
# check_cloudpets_breach("user@example.com")

Note: Replace 'YOUR_API_KEY' with a valid Have I Been Pwned API key. This code queries the Have I Been Pwned API to check if an email was involved in the CloudPets breach.
